INSERT INTO company_questions (company, company_logo_url, difficulty, category, topic, question_text, expected_answer, hints, frequency, last_seen, upvotes, is_verified) VALUES
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Graphs', 'Given a 2D grid of characters and a dictionary, find all words that can be formed by sequentially adjacent cells (Word Search II).', 'Build a Trie from dictionary words. DFS from each cell, following Trie nodes. Mark visited cells during DFS. When reaching a Trie leaf, add word to results. Prune Trie branches for optimization. Time: O(m*n*4^L) where L is max word length.', '["Building a Trie from the dictionary enables efficient prefix checking.", "DFS from each cell following valid Trie paths.", "Prune Trie nodes after finding words to avoid redundant searches."]', 'Very Common', 'Mar 2025', 267, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Dynamic Programming', 'Given a string of parentheses, find the length of the longest valid (well-formed) parentheses substring.', 'DP approach: dp[i] = length of longest valid ending at i. If s[i]=")" and s[i-1]="(": dp[i]=dp[i-2]+2. If s[i]=")" and s[i-1]=")" and s[i-dp[i-1]-1]="(": dp[i]=dp[i-1]+2+dp[i-dp[i-1]-2]. Also solvable with stack. Time: O(n).', '["dp[i] = length of longest valid parentheses ending at index i.", "Consider two cases: ...() and ...))", "Stack approach: push indices, calculate lengths on matching."]', 'Common', 'Feb 2025', 198, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Trees', 'Flatten a binary tree to a linked list in-place (preorder).', 'Morris traversal or recursive approach: for each node, find the rightmost node of left subtree, connect it to right child. Then move left subtree to right and set left to null. Time: O(n), Space: O(1) with Morris.', '["Preorder: root, left, right — flatten in this order.", "For each node, the left subtree should go between the node and its right child.", "Find the rightmost node of left subtree to connect to the right child."]', 'Common', 'Jan 2025', 145, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'System Design', 'System Design', 'Design Google Maps — navigation, real-time traffic, and route computation.', 'Graph representation of road network. Dijkstra/A* for shortest path. Contraction hierarchies for precomputed shortcuts. Real-time traffic: GPS data from phones → traffic speed per road segment. Tile-based map rendering. CDN for map tiles. ETA calculation combining distance + traffic + turn penalties.', '["Road network is a massive weighted graph — how do you route efficiently?", "A* with landmarks provides faster pathfinding than pure Dijkstra.", "How do you incorporate real-time traffic into route calculations?"]', 'Very Common', 'Feb 2025', 312, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Arrays', 'Container With Most Water: given heights array, find two lines that form a container holding the most water.', 'Two pointers: start from both ends. Area = min(height[l], height[r]) * (r-l). Move the pointer with smaller height inward. Track max area. Time: O(n), Space: O(1).', '["Area is limited by the shorter line.", "Start with widest container (both ends) and work inward.", "Moving the shorter pointer might find a taller line to increase area."]', 'Very Common', 'Mar 2025', 189, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Graphs', 'Implement an algorithm to find the shortest path between all pairs of vertices (Floyd-Warshall).', 'Triple nested loop: for each intermediate vertex k, for each pair (i,j): dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]). Initialize with edge weights, infinity for no edge, 0 for diagonal. Time: O(V³), Space: O(V²).', '["Consider each vertex as a potential intermediate stop.", "dp[i][j][k] = shortest path from i to j using vertices 0..k as intermediates.", "Space-optimize: update distance matrix in-place for each k."]', 'Common', 'Jan 2025', 134, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Strings', 'Minimum Window Substring: find the smallest substring of S that contains all characters of T.', 'Sliding window with two pointers. Use a frequency map for T. Expand right until all chars covered. Contract left while still valid — track minimum window. Time: O(|S| + |T|), Space: O(|T|).', '["Use a sliding window that expands and contracts.", "Track how many characters of T are satisfied in the current window.", "Contract from left when all characters are covered to minimize window."]', 'Very Common', 'Mar 2025', 234, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'System Design', 'System Design', 'Design YouTube — video upload, processing, storage, and streaming.', 'Upload: chunked upload to object storage (GCS). Processing pipeline: transcode to multiple resolutions (360p-4K), generate thumbnails, extract metadata. CDN for delivery. Adaptive bitrate streaming (DASH/HLS). Metadata in SQL, video in object storage. Recommendation engine. Content moderation pipeline.', '["Video processing is CPU-intensive — how do you handle upload → playback delay?", "Adaptive bitrate streaming adjusts quality based on user''s bandwidth.", "CDN edge servers reduce latency for global users."]', 'Very Common', 'Feb 2025', 278, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Dynamic Programming', 'Word Break: given a string and a dictionary, determine if the string can be segmented into dictionary words.', 'DP: dp[i] = true if s[0..i-1] can be segmented. For each i, check all j < i: if dp[j] is true and s[j..i-1] is in dictionary, dp[i] = true. Time: O(n² * k) where k is word check time.', '["dp[i] represents whether the first i characters can be segmented.", "For each position, try all possible last words.", "Use a HashSet for O(1) dictionary lookup."]', 'Very Common', 'Mar 2025', 178, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Trees', 'Design and implement a data structure for a Trie (prefix tree) with insert, search, and startsWith.', 'Each node has children map (char → TrieNode) and isEndOfWord flag. Insert: create nodes for each char. Search: follow chars, check isEnd. StartsWith: follow chars, check node exists. Time: O(L) for each operation where L is word length.', '["Each node represents a character in the path from root.", "Children map links to the next character''s node.", "isEndOfWord marks complete words vs prefixes."]', 'Very Common', 'Feb 2025', 167, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Graphs', 'Clone a graph — given a reference to a node, return a deep copy of the entire graph.', 'BFS/DFS with a hash map: original node → cloned node. Visit each node, create clone, recursively clone neighbors. Hash map prevents infinite loops and duplicate cloning. Time: O(V+E), Space: O(V).', '["You need a mapping from original nodes to cloned nodes.", "Use BFS or DFS to traverse the original graph.", "The hash map also serves as a visited set to prevent cycles."]', 'Common', 'Jan 2025', 112, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Dynamic Programming', 'Regular Expression Matching with . and * support.', 'DP: dp[i][j] = s[0..i-1] matches p[0..j-1]. If p[j-1] == s[i-1] or ''.'': dp[i][j] = dp[i-1][j-1]. If p[j-1] == ''*'': dp[i][j] = dp[i][j-2] (zero match) OR (dp[i-1][j] if p[j-2] matches s[i-1]). Time: O(m*n).', '["Handle three cases: literal match, ''.'' wildcard, ''*'' repetition.", "''*'' can mean zero occurrences (skip pattern pair) or one+ occurrences.", "Build the DP table bottom-up considering each case."]', 'Common', 'Dec 2024', 156, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'System Design', 'System Design', 'Design a distributed key-value store like Google Bigtable.', 'LSM tree for writes (memtable → SSTable). Range-partitioned tablets across tablet servers. Master server for tablet assignment. WAL for durability. Bloom filters for read optimization. Compaction to merge SSTables. Replication for fault tolerance. Consistent hashing for load balancing.', '["Writes go to an in-memory table first, then flush to disk.", "How do you partition data across servers for horizontal scaling?", "Bloom filters reduce unnecessary disk reads for non-existent keys."]', 'Rare', 'Nov 2024', 145, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Arrays', 'Product of Array Except Self — return array where each element is the product of all other elements, without division.', 'Two passes: left products (prefix) and right products (suffix). result[i] = left[i] * right[i]. Left pass: running product from left. Right pass: running product from right. Time: O(n), Space: O(1) using result array.', '["You can''t use division — what if there''s a zero?", "For each position, you need the product of everything to its left AND right.", "Two passes: one from left accumulating prefix products, one from right."]', 'Very Common', 'Mar 2025', 198, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Heaps', 'Merge K sorted linked lists into one sorted linked list.', 'Use a min-heap of size K. Insert first node of each list. Extract min, add to result, insert the next node from that list. Time: O(N log K) where N is total nodes. Space: O(K) for heap.', '["A min-heap efficiently finds the smallest among K candidates.", "Always maintain one node from each list in the heap.", "After extracting the min, push its next node into the heap."]', 'Very Common', 'Feb 2025', 234, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Graphs', 'Course Schedule: given prerequisites as pairs, determine if all courses can be finished (cycle detection in DAG).', 'Topological sort using BFS (Kahn''s): count in-degrees, process nodes with in-degree 0. If all processed, no cycle. Or DFS with 3-color marking: white (unvisited), gray (in-progress), black (done). Gray→gray edge = cycle.', '["Model courses and prerequisites as a directed graph.", "If there''s a cycle, some courses can never be completed.", "Topological sort fails if a cycle exists — use this as cycle detection."]', 'Very Common', 'Mar 2025', 189, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'System Design', 'System Design', 'Design a web crawler that can crawl billions of web pages.', 'URL frontier (priority queue) for pages to crawl. DNS resolver cache. Politeness: per-domain rate limiting. Distributed workers pulling URLs. Content dedup via SimHash. URL normalization. Robots.txt compliance. BFS for broad crawl, DFS for deep. Store content in distributed storage. Checkpointing for resume after failures.', '["How do you handle billions of URLs without re-crawling?", "Politeness: respect robots.txt and don''t overwhelm servers.", "Distribution: multiple crawlers pulling from a shared URL frontier."]', 'Common', 'Jan 2025', 167, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Arrays', 'Three Sum: find all unique triplets in an array that sum to zero.', 'Sort array. For each i, use two pointers (j=i+1, k=n-1) to find pairs summing to -arr[i]. Skip duplicates for i, j, and k. Time: O(n²), Space: O(1) excluding result.', '["Sort the array first to enable two-pointer technique.", "Fix one element, then find pairs in the remaining using two pointers.", "Skip duplicate values for all three positions to avoid duplicate triplets."]', 'Very Common', 'Mar 2025', 212, true),
('Google', 'https://logo.clearbit.com/google.com', 'Hard', 'DSA', 'Graphs', 'Find the critical connections (bridges) in a network graph.', 'Tarjan''s bridge finding: DFS with discovery time and low value. An edge (u,v) is a bridge if low[v] > disc[u]. low[v] = min(disc[v], disc of back-edge neighbors, low of DFS-tree children). Time: O(V+E).', '["A bridge is an edge whose removal disconnects the graph.", "Use DFS discovery time and low-link values.", "Edge (u,v) is a bridge if no node in v''s subtree has a back-edge above u."]', 'Common', 'Dec 2024', 145, true),
('Google', 'https://logo.clearbit.com/google.com', 'Medium', 'DSA', 'Dynamic Programming', 'House Robber: can not rob adjacent houses. Find maximum money you can rob.', 'DP: dp[i] = max(dp[i-1], dp[i-2] + nums[i]). At each house, choose to rob (add value + dp[i-2]) or skip (dp[i-1]). Space optimize to two variables. Time: O(n), Space: O(1).', '["At each house: rob it or skip it.", "If you rob house i, you can''t rob house i-1.", "dp[i] = max(skip current, rob current + best from two houses ago)"]', 'Very Common', 'Mar 2025', 156, true);
INSERT INTO company_questions (company, company_logo_url, difficulty, category, topic, question_text, expected_answer, hints, frequency, last_seen, upvotes, is_verified) VALUES
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Trees', 'Validate if a binary tree is a valid BST.', 'Recursive with range: validate(node, min, max). Node value must be in (min, max). Left child: update max to node value. Right child: update min to node value. Use Long.MIN and Long.MAX as initial bounds. Time: O(n).', '["A valid BST: all left subtree values < node < all right subtree values.", "Pass allowable range down the recursion.", "Don''t just check direct children — check entire subtrees."]', 'Very Common', 'Mar 2025', 198, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'System Design', 'System Design', 'Design Amazon''s order processing system handling millions of orders per day.', 'Event-driven architecture: Order Service → Payment Service → Inventory Service → Shipping Service. Saga pattern for distributed transactions. SQS/Kafka for async communication. DynamoDB for order data. State machine for order lifecycle. Idempotent operations. Dead letter queues for failed processing.', '["Each order goes through multiple stages — how do you manage the lifecycle?", "Distributed transactions across services need careful coordination.", "What happens if payment succeeds but inventory is out of stock?"]', 'Very Common', 'Feb 2025', 267, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Arrays', 'Find the maximum area rectangle in a histogram.', 'Stack-based: maintain stack of increasing heights. On smaller height, pop and calculate area with popped height as smallest. Width = current_index - stack_top - 1. Time: O(n), Space: O(n).', '["The area with each bar as height depends on how far it extends left and right.", "A monotonic increasing stack helps find these boundaries.", "Pop when a shorter bar is found — the popped bar''s rectangle ends here."]', 'Very Common', 'Mar 2025', 189, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'HR', 'Behavioral', 'Tell me about a time you showed Customer Obsession. (Amazon Leadership Principle)', 'STAR answer focusing on going above and beyond for a customer/user. Example: noticed users struggling with a feature → conducted user research → redesigned the flow → measured improvement in completion rate. Tie directly to Customer Obsession: starting from the customer and working backwards.', '["Amazon LP: start from the customer and work backwards.", "Give a specific example with measurable customer impact.", "Show that you proactively identified and solved a customer problem."]', 'Very Common', 'Mar 2025', 156, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Graphs', 'Number of connected components in an undirected graph.', 'Use DFS/BFS from each unvisited node — each traversal is one component. Or Union-Find: for each edge, union the two nodes. Count distinct parents. Time: O(V+E) for DFS, O(V+E*α(V)) for Union-Find.', '["Each DFS/BFS from an unvisited node discovers one component.", "Union-Find groups connected nodes into sets.", "Count the number of distinct root parents for components."]', 'Common', 'Jan 2025', 112, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'DSA', 'Dynamic Programming', 'Maximum Profit in Job Scheduling: given jobs with start, end, profit, find max profit without overlapping.', 'Sort by end time. DP: for each job, binary search for latest non-overlapping job. dp[i] = max(dp[i-1], profit[i] + dp[latest_non_overlap]). Time: O(n log n).', '["Sort jobs by end time first.", "For each job, decide: include it or skip it.", "Binary search to find the last job that doesn''t overlap with the current one."]', 'Common', 'Jan 2025', 145, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'HR', 'Behavioral', 'Describe a time you took Ownership of a project that wasn''t originally your responsibility.', 'STAR: identified a project falling behind → volunteered to own it → created a plan, rallied the team, stayed late → delivered successfully. Show you didn''t wait to be asked, took end-to-end responsibility, and thought long-term beyond your immediate scope.', '["Ownership at Amazon means never saying ''that''s not my job''.", "Show you took initiative without being asked.", "Demonstrate end-to-end responsibility and long-term thinking."]', 'Very Common', 'Mar 2025', 134, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Trees', 'Design and implement an LRU Cache.', 'Doubly linked list + HashMap. Get: move to front, return value. Put: if exists, update and move to front. If new, add to front. If capacity exceeded, remove from tail. All operations O(1).', '["Combine constant-time lookup (HashMap) with ordering (linked list).", "Most recently used items at the front, least recently used at the tail.", "On capacity overflow, evict the tail node."]', 'Very Common', 'Mar 2025', 234, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'System Design', 'System Design', 'Design a recommendation system for Amazon product pages ("Customers who bought this also bought").', 'Collaborative filtering: item-item similarity using purchase co-occurrence. Pre-compute item similarity matrix daily. Real-time: given user''s recent purchases, aggregate similar items with scoring. A/B testing for ranking algorithms. Feature store for user preferences. Cold start: popularity-based recommendations.', '["Item-item collaborative filtering: if items are frequently bought together, they''re similar.", "How do you precompute and store similarity scores for millions of products?", "How do you blend different recommendation signals (recent views, purchases, ratings)?"]', 'Very Common', 'Feb 2025', 245, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Strings', 'Longest Substring Without Repeating Characters.', 'Sliding window with HashSet/HashMap. Expand right pointer, if char in set, shrink from left until removed. Track max window length. Time: O(n), Space: O(min(n, charset_size)).', '["Use a sliding window that maintains unique characters.", "Expand right boundary, contract left when a duplicate is found.", "A HashMap storing last index of each char enables O(1) left pointer jump."]', 'Very Common', 'Mar 2025', 198, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Graphs', 'Rotting Oranges: given a grid, find minimum minutes until all oranges rot (multi-source BFS).', 'Multi-source BFS: add all rotten oranges to queue initially. BFS layer by layer (each layer = 1 minute). Fresh oranges adjacent to rotten become rotten. Count minutes. If fresh oranges remain, return -1. Time: O(m*n).', '["Multiple sources rot simultaneously — use multi-source BFS.", "Each BFS layer represents one minute of elapsed time.", "After BFS, check if any fresh oranges remain."]', 'Very Common', 'Feb 2025', 167, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'HR', 'Behavioral', 'Tell me about a time you had to make a decision with Bias for Action despite having incomplete data.', 'STAR: faced a time-sensitive situation → gathered available data → made a calculated decision → course-corrected as new info emerged → positive outcome. Show that you can act decisively and accept calculated risks, while building mechanisms to course-correct.', '["Bias for Action: speed matters in business. Most decisions are reversible.", "Show you acted decisively rather than waiting for perfect information.", "Include how you planned to course-correct if the decision was wrong."]', 'Very Common', 'Mar 2025', 123, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'DSA', 'Trees', 'Serialize and deserialize a binary tree.', 'Preorder DFS: serialize with null markers (e.g., "#"). Deserialize using a queue of tokens: dequeue, if not null create node and recurse left and right. BFS approach also works with level-order. Time: O(n).', '["Choose a traversal that can uniquely reconstruct the tree.", "Preorder with null markers captures full tree structure.", "Deserialization: consume tokens sequentially, building subtrees recursively."]', 'Common', 'Jan 2025', 145, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'System Design', 'System Design', 'Design a distributed cache like Amazon ElastiCache.', 'Consistent hashing for key distribution across cache nodes. LRU eviction policy. Write-through or write-behind strategies. Replication for fault tolerance. Cache stampede prevention with distributed locks. TTL for expiration. Cluster topology management. Health checks and automatic failover.', '["How do you distribute keys across multiple cache servers?", "What happens when a cache server goes down?", "How do you prevent thundering herd when a popular key expires?"]', 'Common', 'Jan 2025', 134, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Dynamic Programming', 'Climbing Stairs: how many distinct ways to reach the top with 1 or 2 steps at a time.', 'DP: dp[i] = dp[i-1] + dp[i-2]. Same as Fibonacci. Base: dp[1]=1, dp[2]=2. Space optimize to two variables. Time: O(n), Space: O(1).', '["At each step, you arrived from either 1 step below or 2 steps below.", "dp[n] = dp[n-1] + dp[n-2] — same recurrence as Fibonacci.", "Only need the last two values — optimize to O(1) space."]', 'Very Common', 'Mar 2025', 112, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'System Design', 'System Design', 'Design Amazon S3 — a highly durable, available, and scalable object storage system.', 'Objects stored in buckets. Data replicated across 3+ AZs. Consistent hashing for data placement. Metadata in distributed KV store. Multipart upload for large files. Versioning with soft deletes. Lifecycle policies for archival. Pre-signed URLs for access control. CDN integration. 11 9s durability via Reed-Solomon erasure coding.', '["How do you achieve 99.999999999% (11 9s) durability?", "Objects can range from bytes to terabytes — how do you handle both?", "How do you manage access control for billions of objects?"]', 'Rare', 'Nov 2024', 189, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Arrays', 'Subarray Sum Equals K: find total number of continuous subarrays whose sum equals K.', 'Prefix sum + HashMap: store count of each prefix sum. For current prefix sum, check how many times (prefix_sum - K) appeared before. Time: O(n), Space: O(n).', '["If prefix_sum[j] - prefix_sum[i] = K, then subarray [i+1..j] sums to K.", "Count occurrences of each prefix sum as you scan.", "For each position, add count of (current_prefix - K) to result."]', 'Very Common', 'Feb 2025', 178, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'HR', 'Behavioral', 'Describe a time you had to Earn Trust from a team or stakeholder who was initially skeptical.', 'STAR: joined a team/project where trust was low → listened actively, delivered on small commitments, shared knowledge openly → gradually earned respect through consistency → outcome: strong collaboration. Show you value transparency, follow through, and earn trust through actions not words.', '["Earn Trust: be honest even when it''s uncomfortable.", "Show you listened first, then acted to build credibility.", "Consistency in small things builds trust for big things."]', 'Common', 'Feb 2025', 112, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Medium', 'DSA', 'Heaps', 'Top K Frequent Elements in an array.', 'Use HashMap for frequency count, then min-heap of size K. Or use bucket sort: index = frequency, value = list of numbers. Time: O(n) with bucket sort, O(n log K) with heap.', '["First count frequencies, then find top K.", "Min-heap of size K: push all, pop when size > K — heap retains top K.", "Bucket sort: frequency as index is O(n) and avoids heap overhead."]', 'Very Common', 'Mar 2025', 167, true),
('Amazon', 'https://logo.clearbit.com/amazon.com', 'Hard', 'DSA', 'Graphs', 'Find the minimum spanning tree of a weighted undirected graph.', 'Kruskal''s: sort edges by weight, add edge if it doesn''t create cycle (Union-Find). Time: O(E log E). Prim''s: start from any node, greedily add cheapest edge connecting to unvisited node (min-heap). Time: O(E log V).', '["MST connects all vertices with minimum total edge weight.", "Kruskal''s: greedy on edges sorted by weight + Union-Find for cycle detection.", "Prim''s: greedy from a starting node, expanding to nearest unvisited."]', 'Common', 'Jan 2025', 134, true);
